#include <iostream>
#include <vector>
#include <queue>
#include <climits>

using namespace std;

typedef pair<int, int> pii;

void add_edge(vector<vector<pii>> &adj, int u, int v, int latency) {
    adj[u].push_back({v, latency});
    adj[v].push_back({u, latency});
}

vector<int> dijkstra(const vector<vector<pii>>& adj, int start, int n) {
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    vector<int> dist(n + 1, INT_MAX);
    pq.push({0, start});
    dist[start] = 0;

    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();

        for (auto& edge : adj[u]) {
            int v = edge.first;
            int weight = edge.second;

            if (dist[v] > dist[u] + weight) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

int main() {
    int n, m, f; // offices (vertices), normal connections, fiber connections
    cin >> n >> m >> f;

    vector<vector<pii>> adj(n + 1); // Adjacency list for graph; adding 1 to handle 1-indexed vertices

    // Read normal connections
    for(int i = 0; i < m; i++) {
        int u, v, latency;
        cin >> u >> v >> latency;
        add_edge(adj, u, v, latency);
    }

    // Fiber connections will be stored but not initially added to the graph
    vector<tuple<int, int, int>> fibers;
    for(int i = 0; i < f; i++) {
        int u, v, latency;
        cin >> u >> latency;
        v = 1; // Assuming office 1 is always the HQ
        fibers.emplace_back(u, v, latency); 
    }

    vector<int> original = dijkstra(adj, 1, n); // Shortest paths from HQ with only normal connections

    int removableFibers = 0;
    for(auto& fiber : fibers) {
        int u, v, latency;
        tie(u, v, latency) = fiber;
        add_edge(adj, u, v, latency); // Temporarily add fiber connection

        vector<int> withFiber = dijkstra(adj, 1, n); // Calculate shortest paths with this fiber connection
        bool isRemovable = true;
        for(int i = 1; i <= n; i++) {
            // Check if this fiber connection affects any shortest path.
            if(withFiber[i] != original[i]) {
                isRemovable = false;
                break;
            }
        }

        if(isRemovable) removableFibers++; // If Shortest paths are unaffected, fiber is removable

        // Remove the fiber connection after check
        adj[u].pop_back(); // Assuming this is the last added edge
        adj[v].pop_back();
    }

    cout << removableFibers << endl;

    return 0;
}
